import React from "react";
import { useParams } from "react-router-dom";

import PlaceList from "../components/PlaceList";


const DUMMY_PLACES = [
  {
    id: "p1",
    title: "DWARKADHISH TEMPLE DWARKA",
    description: "Dwarka has the Dwarkadhish Temple dedicated to Krishna, which is one of four sacred Hindu pilgrimage sites called the Chardham.",
    imageUrl: " https://www.chardham-pilgrimage-tour.com/assets/images/dwarkadish-chardham-temple-04.webp",
    address:"Dwarka, Gujarat 361335",
    location: {
      lat: 22.2376811,
      lng: 68.9673582
    },
    creator: "u1"
  },
  {
    id: "p2",
    title: "SOMNATH JYOTIRLING TRMPLE",
    description:
      "the first of the twelve Jyotirlinga shrines dedicated to Lord Shiva.",
    imageUrl:"https://dwq3yv87q1b43.cloudfront.net/public/blogs/fit-in/1350x300/Blog_20241119-522495206-1732013466.jpg",
    address:"Somnath Mandir Rd, Somnath, Prabhas Patan, Gujarat 362268",
    location: {
      lat: 20.8879899,
      lng: 70.398682
    },
    creator: "u2"
  },

  { 
    id: 'p3', 
    title: ' Canda(Moraine Lake)',
     description: 'Moraine Lake is a snow and glacially fed alpine lake in Banff National Park, 14 kilometres outside the village of Lake Louise, Alberta, Canada. ',
      imageUrl: 'https://banfflakelouise.bynder.com/m/3d04f19979f432ec/2000x1080_jpg-2022_MoraineLake_TravelAlberta_RothandRamberg-3.jpg',
       location: { 
        lat: 51.3215507, 
        lng: -116.1952415, 
    }, 
       creator: 'u3' 
    },

{
     id: 'p4',
      title: ' India( jaipur,hawa Mahal)',
       description: 'The Hawa Mahal is a palace in the city of Jaipur, Rajasthan, India. Built from red and pink sandstone, it is on the edge of the City Palace, Jaipur. ', 
       imageUrl: 'https://www.tourmyindia.com/images/hawa-mahal-fort-jaipur.jpg',
        location: { 
            lat: 26.9240458, 
            lng: 75.8267144, }, 
            creator: 'u4' 
        },
        { 
            id: 'p5',
             title: ' Africa( Pyramids of Giza)',
              description: 'Perhaps the most iconic ancient landmarks in Africa, the Pyramids of Giza are also among the greatest mysteries on the planet. ',
               imageUrl: 'https://dailypassport.com/wp-content/uploads/sites/8/2023/07/1-DP-Ancient-Landmarks-Africa.jpg?resize=1024,768',
                location: { 
                    lat: 29.9772962, 
                    lng: 31.1299206, },
                     creator: 'u5'
                    
                    }
];

const UserPlaces = () => {
  const userId = useParams().userId;

  const loadedPlaces = DUMMY_PLACES.filter(
    place => place.creator === userId
  );

  return <PlaceList items={loadedPlaces} />;
};

export default UserPlaces;
